struct TestConfig {
    name: &'static str,
    sample_rate: i32,
    /// C decoder HP filter delay in samples
    c_decoder_delay: usize,
    packets: [&'static str; 10],
    /// C decoder PCM output (includes HP filter delay at start)
    c_decoded_pcm: [&'static str; 10],
}

fn test_configs() -> Vec<TestConfig> {
    vec![
        TestConfig {
            name: "nb_8000hz_10000bps",
            sample_rate: 8000,
            c_decoder_delay: 5,
            packets: [
                PKT_NB_0, PKT_NB_1, PKT_NB_2, PKT_NB_3, PKT_NB_4, PKT_NB_5, PKT_NB_6, PKT_NB_7,
                PKT_NB_8, PKT_NB_9,
            ],
            c_decoded_pcm: [
                PCM_NB_0, PCM_NB_1, PCM_NB_2, PCM_NB_3, PCM_NB_4, PCM_NB_5, PCM_NB_6, PCM_NB_7,
                PCM_NB_8, PCM_NB_9,
            ],
        },
        TestConfig {
            name: "wb_16000hz_20000bps",
            sample_rate: 16000,
            c_decoder_delay: 13,
            packets: [
                PKT_WB_0, PKT_WB_1, PKT_WB_2, PKT_WB_3, PKT_WB_4, PKT_WB_5, PKT_WB_6, PKT_WB_7,
                PKT_WB_8, PKT_WB_9,
            ],
            c_decoded_pcm: [
                PCM_WB_0, PCM_WB_1, PCM_WB_2, PCM_WB_3, PCM_WB_4, PCM_WB_5, PCM_WB_6, PCM_WB_7,
                PCM_WB_8, PCM_WB_9,
            ],
        },
    ]
}

#[test]
fn silk_decoder_matches_c_libopus_fixed_point() {
    for cfg in test_configs() {
        let mut decoder = OpusDecoder::new(cfg.sample_rate, 1)
            .unwrap_or_else(|e| panic!("Failed to create decoder for {}: {:?}", cfg.name, e));

        let frame_size = (cfg.sample_rate / 50) as usize; // 20ms frames

        // Decode all frames and collect into a stream
        let mut rust_stream: Vec<i16> = Vec::new();
        let mut c_stream: Vec<i16> = Vec::new();

        for (frame_idx, (pkt_hex, c_pcm_hex)) in
            cfg.packets.iter().zip(cfg.c_decoded_pcm.iter()).enumerate()
        {
            let packet = hex_to_bytes(pkt_hex);
            let c_pcm = hex_to_i16_le(c_pcm_hex);
            c_stream.extend_from_slice(&c_pcm);

            let mut output = vec![0.0f32; frame_size];
            let n_samples = decoder
                .decode(&packet, frame_size, &mut output)
                .unwrap_or_else(|e| {
                    panic!(
                        "Decode failed for {} frame {}: {:?}",
                        cfg.name, frame_idx, e
                    )
                });

            assert_eq!(
                n_samples, frame_size,
                "Unexpected sample count for {} frame {}",
                cfg.name, frame_idx
            );

            for &x in &output[..n_samples] {
                rust_stream.push((x * 32768.0).round().max(-32768.0).min(32767.0) as i16);
            }
        }

        // Compare streams: C output has `c_decoder_delay` extra samples at the start
        // (from the HP filter), so C[delay..] should match Rust[..len-delay]
        let delay = cfg.c_decoder_delay;
        let compare_len = rust_stream.len().min(c_stream.len() - delay);

        for i in 0..compare_len {
            let rust_val = rust_stream[i];
            let c_val = c_stream[i + delay];
            assert_eq!(
                rust_val,
                c_val,
                "PCM mismatch at {} sample {} (C offset {}): Rust={} (0x{:04x}) C={} (0x{:04x})",
                cfg.name,
                i,
                i + delay,
                rust_val,
                rust_val as u16,
                c_val,
                c_val as u16
            );
        }

        eprintln!(
            "PASS: {} — {} samples match (C delay={})",
            cfg.name, compare_len, delay
        );
    }
}
